export async function updatePersona(id: string, patch: PersonaUpdate): Promise<void> {
  const description = buildPersonaDescription(patch);

  // Snapshot old inventory before the update so we can detect new items.
  const old = await getPersona(id);
  const oldItemNames = old
    ? new Set(old.inventory.map((i) => i.item.toLowerCase()))
    : new Set<string>();

  await execute(
    `UPDATE personas SET name = $2, description = $3, gender = $4, age = $5, race = $6, appearance = $7, skills = $8, inventory = $9, updated_at = $10 WHERE id = $1`,
    [
      id, patch.name, description,
      patch.gender, patch.age, patch.race, patch.appearance,
      JSON.stringify(patch.skills), JSON.stringify(patch.inventory),
      nowIso(),
    ],
  );

  // Auto-illustration: enqueue for newly added inventory items without images.
  for (const entry of patch.inventory) {
    if (!oldItemNames.has(entry.item.toLowerCase()) && !entry.image_path) {
      const { enqueueIllustration } = await import("../../memory/imageGenQueue");
      enqueueIllustration(
        "inventory",
        id,
        `Fantasy RPG item: ${entry.item}`,
        entry.item,
      );
    }
  }
}

